import re, glob, collections

raw = []
for f in glob.glob("*.ipynb"):
    with open(f) as fh:
        for m in re.findall(r'##(Figure[^#]*)##', fh.read()):
            raw.append(m.strip())

def base(lbl):
    # strip position suffixes like top/bottom/left/right/mid
    return re.sub(r'(top|bottom|left|right|mid)$', '', lbl)

panels = set()
for lbl in raw:
    lbl = base(lbl)
    m = re.match(r'(Figure(?:S)?\d+)([a-z])-([a-z])$', lbl)  # range e.g. Figure5a-c
    if m:
        prefix, a, b = m.group(1), m.group(2), m.group(3)
        for c in range(ord(a), ord(b)+1):
            panels.add(prefix + chr(c))
    else:
        panels.add(lbl)

# group by figure
byfig = collections.defaultdict(list)
for p in panels:
    m = re.match(r'(Figure(?:S)?\d+)([a-z].*)', p)
    if m:
        byfig[m.group(1)].append(m.group(2))

def figkey(k):
    s = k.startswith('FigureS')
    n = int(re.search(r'\d+', k).group())
    return (s, n)

total = 0
for fig in sorted(byfig, key=figkey):
    ps = sorted(set(byfig[fig]))
    total += len(ps)
    print(f"{fig}: {len(ps)} panels -> {', '.join(ps)}")
print(f"\nTOTAL unique panels labeled: {total}")
