import json,re,csv,glob
from collections import defaultdict,Counter
jmap=json.load(open("manuscript_figure_panel_map.json"))
CATNAME={1:"1_matched_to_code",2:"2_example_regeneration",3:"3_cartoon_no_csv",4:"4_missing"}
track=defaultdict(dict)
for r in list(csv.reader(open("combined_panel_tracking.csv")))[1:]:
    if not r or r[0]=="TOTAL": continue
    for col in (1,2,3,4):
        cell=r[col] if col<len(r) else ""
        for p in cell.split(","):
            p=p.strip()
            if p: track[r[0]][p]=col
labre=re.compile(r'##+(Figure(?:S)?\d+[a-z][A-Za-z0-9_\-]*)##+')
def expand(lbl):
    m=re.match(r'(Figure(?:S)?\d+)([a-z])-([a-z])$',lbl)
    if m: return [f"{m.group(1)}{chr(x)}" for x in range(ord(m.group(2)),ord(m.group(3))+1)]
    return [re.sub(r'_version\d*$','',lbl)]
fig_cov=defaultdict(set); csv_cov=defaultdict(set)
for nb in glob.glob("*.ipynb"):
    short=nb.split(".ipynb")[0]; doc=json.load(open(nb))
    for c in doc["cells"]:
        if c["cell_type"]!="code": continue
        s="".join(c["source"]); labels=labre.findall(s)
        if not labels: continue
        hf=('save_panels(' in s) or ('panels=' in s); hc=('save_panel_csv(' in s) or ('panels=' in s)
        for lbl in labels:
            for pid in expand(lbl):
                if hf: fig_cov[pid].add(short)
                if hc: csv_cov[pid].add(short)
def figkey(f): return (f.startswith('FigureS'), int(re.search(r'\d+',f).group()))
rows=[["panel","category","figure_generated","csv_generated","notebook"]]
for fig in sorted(jmap,key=figkey):
    for key in jmap[fig]:
        pid=f"{fig}{key}"; cat=track.get(fig,{}).get(key)
        rows.append([pid, CATNAME.get(cat,"(not in tracking)"),
                     "Yes" if pid in fig_cov else "No", "Yes" if pid in csv_cov else "No",
                     "; ".join(sorted(fig_cov.get(pid,set())|csv_cov.get(pid,set())))])
csv.writer(open("panel_coverage_audit.csv","w",newline="")).writerows(rows)
print(f"Wrote panel_coverage_audit.csv ({len(rows)-1} panels)")
print("category:", dict(Counter(r[1] for r in rows[1:])))
print("figure_generated:", dict(Counter(r[2] for r in rows[1:])), "csv_generated:", dict(Counter(r[3] for r in rows[1:])))
print("\nAnomalies:")
none=True
for r in rows[1:]:
    pid,cat,fg,cg,nb=r
    if cat=="(not in tracking)" or (cat=="1_matched_to_code" and fg=="No") or (fg=="Yes" and cat!="1_matched_to_code") or fg!=cg:
        print(f"   {pid}: cat={cat} fig={fg} csv={cg} nb={nb}"); none=False
if none: print("   (none)")
